#!/usr/bin/env bash
set -euo pipefail; source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;wrapper=org.archphene.linux.p0392be9c9f103a39d951c2f39c3644d2;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--wrapper)wrapper="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";manager=org.archpheneos.manager;packages="$(archphene_adb_run shell cmd package list packages -U)";uid(){ sed -n "s/^package:$1 uid:\([0-9]*\).*/\1/p"<<<"$packages"|head -n1;};manager_uid="$(uid "$manager")";wrapper_uid="$(uid "$wrapper")";[[ -n "$manager_uid" && -n "$wrapper_uid" && "$manager_uid" != "$wrapper_uid" ]] || archphene_die 'manager and wrapper require distinct UIDs';activity="$(archphene_launcher "$wrapper")";archphene_adb_run logcat -c;archphene_adb_run shell am force-stop "$wrapper";archphene_adb_run shell am start -W -n "$activity" >/dev/null;lease="$(archphene_wait_log "Acquired runtime pack lease [a-f0-9]{64} for $wrapper" 30)";pack="$(python3 -c 'import re,sys;m=re.search(r"Acquired runtime pack lease ([a-f0-9]{64})",sys.stdin.read());print(m.group(1) if m else "")'<<<"$lease")";pid="$(archphene_adb_run shell pidof "$wrapper"|tr -d '\r')";deadline=$((SECONDS+30));linux=;while ((SECONDS<deadline));do linux="$(archphene_adb_run shell ps -A -o PID,PPID,NAME|awk -v p="$pid" '$2==p && $3=="loader"{print $1;exit}')";[[ -n "$linux" ]] && break;sleep .5;done;[[ -n "$linux" ]] || archphene_die 'managed loader missing';fds="$(archphene_adb_run shell run-as "$wrapper" ls -l "/proc/$linux/fd")";archphene_regex_contains "$fds" 'runtime-fd-[^/]+/\.program' && archphene_regex_contains "$fds" 'runtime-fd-[^/]+/\.library-' || archphene_die 'bounded executable view missing';live="$(archphene_adb_run shell run-as "$wrapper" du -sk cache|awk '{print $1}')";((live>0 && live<524288)) || archphene_die "cache outside bound: $live";archphene_adb_run shell input keyevent 4;archphene_wait_log "(Released runtime pack lease|Runtime process died; released pack lease) $pack" 20 >/dev/null;deadline=$((SECONDS+20));clean=$live;while ((SECONDS<deadline));do clean="$(archphene_adb_run shell run-as "$wrapper" du -sk cache|awk '{print $1}')";((clean<65536)) && break;sleep .5;done;((clean<65536)) || archphene_die 'wrapper retained runtime closure';archphene_note "Runtime-pack execution passed: manager UID $manager_uid -> wrapper UID $wrapper_uid; pack $pack, cache $live -> $clean KiB."
